import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





export default function Component(props: Props) {
  const [step, setStep] = useState(1);
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    satisfaction: 3,
    features: [] as string[],
    comments: ''
  });

  const [errors, setErrors] = useState({ email: '' });

  const validateEmail = (email: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

  const isCurrentStepValid = useMemo(() => {
    if (step === 1) return formData.name.trim() !== '' && validateEmail(formData.email);
    return true;
  }, [step, formData]);

  const handleNext = () => setStep((s) => Math.min(s + 1, 4));
  const handleBack = () => setStep((s) => Math.max(s - 1, 1));

  const submit = useAction<ActionSubmitPayload>('submit');

  const renderStep = () => {
    switch (step) {
      case 1:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Input label="Name" placeholder="Enter your name" value={formData.name} onChange={(val) => setFormData({ ...formData, name: val })} />
            <Input label="Email" placeholder="you@example.com" value={formData.email} error={errors.email} onChange={(val) => { setFormData({ ...formData, email: val }); setErrors({ email: validateEmail(val) ? '' : 'Invalid email format' }); }} />
          </Stack>
        );
      case 2:
        return (
          <Stack gap="var(--ggui-spacing-4)">
            <Text variant="label">How satisfied are you?</Text>
            <RadioGroup value={formData.satisfaction.toString()} onChange={(val) => setFormData({ ...formData, satisfaction: parseInt(val) })} options={props.satisfactionLabels.map((l, i) => ({ label: l, value: (i + 1).toString() }))} />
            <Text variant="label">Interested Features</Text>
            {props.featureOptions.map((f) => (
              <Checkbox key={f} label={f} checked={formData.features.includes(f)} onChange={(checked) => setFormData({ ...formData, features: checked ? [...formData.features, f] : formData.features.filter((x) => x !== f) })} />
            ))}
          </Stack>
        );
      case 3:
        return <TextArea label="Comments" value={formData.comments} onChange={(val) => setFormData({ ...formData, comments: val })} maxLength={500} showCount rows={4} />;
      case 4:
        return (
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={4}>Review Your Answers</Heading>
            <Text>Name: {formData.name}</Text>
            <Text>Email: {formData.email}</Text>
            <Text>Satisfaction: {formData.satisfaction}</Text>
            <Text>Features: {formData.features.join(', ') || 'None'}</Text>
            <Text>Comments: {formData.comments || 'No comments'}</Text>
          </Stack>
        );
    }
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={2}>Survey</Heading>
          <Progress value={step - 1} max={3} />
          <Text variant="caption">Step {step} of 4</Text>
        </Stack>

        <Card padding="var(--ggui-spacing-6)">
          {renderStep()}
        </Card>

        <Row gap="var(--ggui-spacing-4)" justify="between">
          <Button variant="ghost" disabled={step === 1} as={Clickable} onClick={handleBack}>Back</Button>
          {step < 4 ? (
            <Button variant="primary" disabled={!isCurrentStepValid} as={Clickable} onClick={handleNext}>Next</Button>
          ) : (
            <Button variant="primary" as={Clickable} onClick={() => submit(formData as ActionSubmitPayload)}>Submit</Button>
          )}
        </Row>
        </Row>
      </Stack>
    </Container>
  );
}

