import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  const [boardTasks, setBoardTasks] = useState(props.tasks || []);
  const [activeAddTaskCol, setActiveAddTaskCol] = useState<string | null>(null);
  const [newTaskForm, setNewTaskForm] = useState({ title: '', priority: 'medium' as 'low' | 'medium' | 'high' });
  const [editingTaskId, setEditingTaskId] = useState<string | null>(null);
  const [editingTitle, setEditingTitle] = useState('');
  const taskUpdateAction = useAction<ActionTaskUpdatePayload>('taskUpdate');
  const streamUpdate = useStream<StreamTaskChanged>('taskChanged');
  const stats = useMemo(() => ({ total: boardTasks.length, done: boardTasks.filter(t => t.column === 'done').length }), [boardTasks]);
  useEffect(() => {
    if (streamUpdate.latest?.task) {
      const { task, action } = streamUpdate.latest;
      if (task?.id) {
        if (action === 'delete') setBoardTasks(prev => prev.filter(t => t.id !== task.id));
        else setBoardTasks(prev => {
          const exists = prev.find(t => t.id === task.id);
          return exists ? prev.map(t => t.id === task.id ? { ...t, ...task } : t) : [...prev, task];
        });
      }
    }
  }, [streamUpdate.latest]);
  const handleAddTask = (columnId: string) => {
    const newTask = { id: Math.random().toString(), title: newTaskForm.title, priority: newTaskForm.priority, column: columnId, assignee: 'Me' };
    setBoardTasks(prev => [...prev, newTask]);
    taskUpdateAction({ action: 'create', taskId: newTask.id, data: { column: columnId } });
    setActiveAddTaskCol(null);
    setNewTaskForm({ title: '', priority: 'medium' });
  };
  const moveTask = (taskId: string, newColumn: string) => {
    setBoardTasks(prev => prev.map(t => t.id === taskId ? { ...t, column: newColumn } : t));
    taskUpdateAction({ action: 'move', taskId, data: { column: newColumn } });
  };
  const handleEditTask = (taskId: string, title: string) => {
    setBoardTasks(prev => prev.map(t => t.id === taskId ? { ...t, title } : t));
    taskUpdateAction({ action: 'edit', taskId, data: { column: boardTasks.find(t => t.id === taskId)?.column || '' } });
    setEditingTaskId(null);
  };
  const activeColumns = props.columns || [{ id: 'todo', name: 'To Do' }, { id: 'in-progress', name: 'In Progress' }, { id: 'done', name: 'Done' }];

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={2}>Kanban Board</Heading>
            <Row gap="var(--ggui-spacing-4)">
              <Badge>Total: {stats.total}</Badge>
              <Badge>Done: {stats.done}</Badge>
            </Row>
          </Row>
        </Card>
        <Row gap="var(--ggui-spacing-4)" align="start">
          {activeColumns.map(col => (
            <Stack key={col.id} gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: 250 }}>
              <Box padding="var(--ggui-spacing-2)" background="var(--ggui-color-neutral-100)">
                <Row justify="between" align="center">
                  <Heading level={4}>{col.name}</Heading>
                  <Badge>{boardTasks.filter(t => t.column === col.id).length}</Badge>
                </Row>
              </Box>
              {boardTasks.filter(t => t.column === col.id).map(task => (
                <Card key={task.id} padding="var(--ggui-spacing-3)">
                  <Stack gap="var(--ggui-spacing-2)">
                    {editingTaskId === task.id ? (
                      <Input label="" value={editingTitle} onChange={setEditingTitle} onBlur={() => handleEditTask(task.id!, editingTitle)} />
                    ) : (
                      <Text as={Clickable} onClick={() => { setEditingTaskId(task.id!); setEditingTitle(task.title!); }}>{task.title}</Text>
                    )}
                    <Row justify="between" align="center">
                      <Avatar>{task.assignee}</Avatar>
                      <Text size="sm" color="var(--ggui-color-neutral-600)">{task.dueDate}</Text>
                    </Row>
                    <Row justify="between" align="center">
                      <Badge variant={task.priority === 'high' ? 'error' : task.priority === 'medium' ? 'warning' : 'info'}>{task.priority}</Badge>
                      <Select label="" options={activeColumns.filter(c => c.id !== col.id).map(c => ({ value: c.id!, label: `Move to ${c.name}` }))} onChange={(val) => moveTask(task.id!, val)} />
                    </Row>
                  </Stack>
                </Card>
                ))}
                {activeAddTaskCol === col.id ? (
                <Card padding="var(--ggui-spacing-3)">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Input label="Title" value={newTaskForm.title} onChange={(val) => setNewTaskForm(prev => ({...prev, title: val}))} />
                    <Select label="Priority" value={newTaskForm.priority} onChange={(val) => setNewTaskForm(prev => ({...prev, priority: val as any}))} options={[{value:'low', label:'Low'}, {value:'medium', label:'Medium'}, {value:'high', label:'High'}]} />
                    <Row gap="var(--ggui-spacing-2)">
                      <Button as={Clickable} onClick={() => handleAddTask(col.id!)}>Save</Button>
                      <Button as={Clickable} onClick={() => setActiveAddTaskCol(null)}>Cancel</Button>
                    </Row>
                  </Stack>
                </Card>
              ) : (
                <Button as={Clickable} fullWidth onClick={() => setActiveAddTaskCol(col.id!)}>Add Task</Button>
              )}
            </Stack>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

