// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





const CATEGORY_COLORS: Record<string, string> = {
  'alkali-metal': 'var(--ggui-color-primary-400)',
  'alkaline-earth-metal': 'var(--ggui-color-primary-300)',
  'transition-metal': 'var(--ggui-color-primary-500)',
  'post-transition-metal': 'var(--ggui-color-primary-600)',
  'metalloid': 'var(--ggui-color-success-400)',
  'reactive-nonmetal': 'var(--ggui-color-warning-400)',
  'noble-gas': 'var(--ggui-color-info-400)',
  'lanthanide': 'var(--ggui-color-secondary-300)',
  'actinide': 'var(--ggui-color-secondary-400)',
};

const CATEGORIES = [
  { name: 'Alkali Metal', color: 'var(--ggui-color-primary-400)' },
  { name: 'Alkaline Earth Metal', color: 'var(--ggui-color-primary-300)' },
  { name: 'Transition Metal', color: 'var(--ggui-color-primary-500)' },
  { name: 'Post-transition Metal', color: 'var(--ggui-color-primary-600)' },
  { name: 'Metalloid', color: 'var(--ggui-color-success-400)' },
  { name: 'Reactive Nonmetal', color: 'var(--ggui-color-warning-400)' },
  { name: 'Noble Gas', color: 'var(--ggui-color-info-400)' },
  { name: 'Lanthanide', color: 'var(--ggui-color-secondary-300)' },
  { name: 'Actinide', color: 'var(--ggui-color-secondary-400)' },
];


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<typeof props.elements[0] | null>(null);


  const filteredElements = useMemo(() => {
    return (props.elements || []).filter(el => 
      (el.name?.toLowerCase().includes(searchTerm.toLowerCase()) || 
       el.symbol?.toLowerCase().includes(searchTerm.toLowerCase()))
    );
  }, [props.elements, searchTerm]);

  return (
    <Container maxWidth="3xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Heading level={1}>Periodic Table</Heading>
        <Input label="Search Elements" placeholder="Search by name or symbol..." value={searchTerm} onChange={(val: string) => setSearchTerm(val)} />

        <Box style={{ display: 'grid', gridTemplateColumns: 'repeat(18, 1fr)', gap: 'var(--ggui-spacing-1)' }}>
          {(props.elements || []).map((el, i) => (
            <Card
              key={i}
              as={Hoverable}
              onFocus={() => {}}
              tabIndex={0}
              className="element-card"
              onClick={() => setSelectedElement(el)}
              padding="var(--ggui-spacing-2)"
              style={{
                gridRow: el.row,
                gridColumn: el.col,
                backgroundColor: el.category ? (CATEGORY_COLORS[el.category] || 'var(--ggui-color-surfaceVariant)') : 'var(--ggui-color-surfaceVariant)',
                opacity: searchTerm && !filteredElements.includes(el) ? 0.2 : 1,
                cursor: 'pointer',
                transition: 'transform 0.2s, box-shadow 0.2s'
              }}
              border={true}
              onMouseEnter={(e: any) => { e.currentTarget.style.transform = 'scale(1.1)'; e.currentTarget.style.boxShadow = '0 4px 8px rgba(0,0,0,0.1)'; }}
              onMouseLeave={(e: any) => { e.currentTarget.style.transform = 'scale(1)'; e.currentTarget.style.boxShadow = 'none'; }}
            >

              <Text variant="caption" style={{ fontSize: '10px' }}>{el.atomicNumber}</Text>
              <Heading level={4} align="center">{el.symbol}</Heading>
            </Card>
          ))}
        </Box>

        <Card padding="var(--ggui-spacing-4)">
          <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
            {CATEGORIES.map(cat => (
              <Row key={cat.name} align="center" gap="var(--ggui-spacing-1)">
                <Box style={{ width: 12, height: 12, backgroundColor: cat.color, borderRadius: '2px' }} />
                <Text variant="caption">{cat.name}</Text>
              </Row>
            ))}
          </Stack>
        </Card>

        {selectedElement && (
          <Card padding="var(--ggui-spacing-6)">
            <Heading level={2}>{selectedElement.name}</Heading>
            <Stack gap="var(--ggui-spacing-2)">
              <Text>Symbol: {selectedElement.symbol}</Text>
              <Text>Atomic Number: {selectedElement.atomicNumber}</Text>
              <Text>Atomic Weight: {selectedElement.atomicWeight}</Text>
              <Text>Category: {selectedElement.category}</Text>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

