const StarRating = ({ rating }: { rating: number }) => (
  <Row gap="var(--ggui-spacing-1)">
    {[1, 2, 3, 4, 5].map((i) => (
      <Icon
        key={i}
        name={i <= Math.round(rating) ? 'star' : 'star-outline'}
