      />
    ))}
  </Row>
);

export default function Component(props: Props) {
  const addToCartAction = useAction<ActionAddToCartPayload>('addToCart');
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  const stock = props.product.stock || 0;
  const inStock = stock > 0;
  const isLowStock = stock > 0 && stock <= 5;

  const handleAddToCart = useCallback(() => {
    if (props.product.id) {
      addToCartAction({ productId: props.product.id, quantity });
    }
  }, [addToCartAction, props.product.id, quantity]);

  const specs = (props.product.specifications as { key: string; value: string }[]) || [];
  const reviews = (props.product.reviews as { author: string; rating: number; text: string; date: string }[]) || [];

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        <Row gap="var(--ggui-spacing-8)" align="start" wrap={true}>
          <Box
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-12)"
            style={{ flex: 1, minWidth: '300px', display: 'flex', justifyContent: 'center' }}
          >
            <Image
              src="/placeholder.png"
              alt={props.product.name || 'Product image'}
              width={200}
              height={200}
            />
          </Box>

          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{props.product.name}</Heading>
            <Text variant="bodyLarge" weight="bold">
              {props.product.currency}
              {props.product.price?.toFixed(2)}
            </Text>
            <StarRating rating={props.product.rating || 0} />
            <Badge variant={isLowStock ? 'warning' : 'success'}>
              {inStock ? (isLowStock ? 'Low Stock' : 'In Stock') : 'Out of Stock'}
            </Badge>

            <Spacer size={16} />

              <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="end">
                <Button variant="outline" size="sm" onClick={() => setQuantity((q) => Math.max(1, q - 1))}>-</Button>
                <Input
                  label="Quantity"
                  type="number"
                  value={quantity.toString()}
                  onChange={(val: string) => {
                    const valNum = parseInt(val, 10);
                    if (!isNaN(valNum) && valNum >= 1 && valNum <= stock) setQuantity(valNum);
                  }}
                  style={{ width: '60px' }}
                />
                <Button variant="outline" size="sm" onClick={() => setQuantity((q) => Math.min(stock, q + 1))}>+</Button>
                <Button
                  variant="primary"
                  disabled={!inStock}
                  onClick={handleAddToCart}
                >
                  Add to Cart
                </Button>
              </Stack>
          </Stack>
        </Row>

        <Card padding="var(--ggui-spacing-4)">
          <Tabs
            activeKey={activeTab}
            onChange={(key) => setActiveTab(key as string)}
            items={[
              {
                key: 'description',
                label: 'Description',
                content: <Text>{props.product.description}</Text>,
              },
              {
                key: 'specifications',
                label: 'Specifications',
                content: (
                  <Table
                    columns={[{ key: 'key', header: 'Feature' }, { key: 'value', header: 'Detail' }]}
                    data={specs}
                  />
                ),
              },
              {
                key: 'reviews',
                label: 'Reviews',
                content: (
                  <Stack gap="var(--ggui-spacing-4)">
                    {reviews.map((r: any, i: number) => (
                      <Card key={i} padding="var(--ggui-spacing-3)">
                        <Text weight="semibold">{r.author} - {r.rating} stars</Text>
                        <Text variant="caption">{r.date}</Text>
                        <Text>{r.text}</Text>
                      </Card>
                    ))}
                  </Stack>
                ),
              },
            ]}
          />
        </Card>
      </Stack>
    </Container>
  );
}

