interface Props {
  title: string; // Chat window title
  currentUser: string; // Current user name (for right-aligning own messages)
  participantCount: number; // Number of participants
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>; // Initial messages to display on mount
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




const MessageGroup = ({ messages, isOwn, sender }: { messages: Array<{ text?: string; timestamp?: string }>; isOwn: boolean; sender?: string }) => (
  <Stack align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-1)">
    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
      {sender || 'Unknown'}
    </Text>
    {messages.map((m, i) => (
      <Stack key={i} align={isOwn ? 'end' : 'start'} gap="var(--ggui-spacing-0-5)">
        <Box
          paddingX="var(--ggui-spacing-3)"
          paddingY="var(--ggui-spacing-2)"
          background={isOwn ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)'}
          borderRadius="var(--ggui-shape-radius-lg)"
        >
          <Text color={isOwn ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-onSurface)'}>{m.text}</Text>
        </Box>
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          {new Date(m.timestamp || Date.now()).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </Text>
      </Stack>
    ))}
  </Stack>
);


const getMessageGroups = (messages: Array<{ sender?: string; text?: string; timestamp?: string }>) => {
  const groups: Array<{ sender: string; messages: Array<{ text?: string; timestamp?: string }> }> = [];
  messages.forEach((m) => {
    const sender = m.sender || 'Unknown';
    if (groups.length > 0 && groups[groups.length - 1].sender === sender) {
      groups[groups.length - 1].messages.push({ text: m.text, timestamp: m.timestamp });
    } else {
      groups.push({ sender, messages: [{ text: m.text, timestamp: m.timestamp }] });
    }
  });
  return groups;
};



export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag
  const [input, setInput] = useState('');
  const [localMessages, setLocalMessages] = useState(props.messages || []);
  const [typingUsers, setTypingUsers] = useState<Set<string>>(new Set());
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (message.latest) {
      setLocalMessages((prev) => [...prev, message.latest!]);
    }
  }, [message.latest]);

  useEffect(() => {
    if (typing.latest) {
      setTypingUsers((prev) => {
        const next = new Set(prev);
        if (typing.latest?.active) {
          next.add(typing.latest.sender || 'Someone');
        } else {
          next.delete(typing.latest?.sender || 'Someone');
        }
        return next;
      });
    }
  }, [typing.latest]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [localMessages, typingUsers]);

  const handleSend = useCallback(() => {
    if (!input.trim()) return;
    sendMessage({ text: input, timestamp: new Date().toISOString() });
    setLocalMessages((prev) => [...prev, { sender: props.currentUser, text: input, timestamp: new Date().toISOString() }]);
    setInput('');
  }, [input, props.currentUser, sendMessage]);

  const groupedMessages = useMemo(() => getMessageGroups(localMessages), [localMessages]);

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-4)">
      <Card padding="var(--ggui-spacing-4)">
        <Stack gap="var(--ggui-spacing-4)">
          <Row justify="between" align="center">
            <Heading level={3}>{props.title}</Heading>
            <Badge>{props.participantCount} online</Badge>
          </Row>

          <Box
            background="var(--ggui-color-surface)"
            padding="var(--ggui-spacing-2)"
            style={{ height: '400px', overflowY: 'auto' }}
            ref={scrollRef}
            role="log"
            aria-label="Messages"
          >

            <Stack gap="var(--ggui-spacing-4)">
              {groupedMessages.map((group, i) => (
                <MessageGroup
                  key={i}
                  sender={group.sender}
                  messages={group.messages}
                  isOwn={group.sender === props.currentUser}
                />
              ))}
              {typingUsers.size > 0 && (
                <Text variant="caption" color="var(--ggui-color-primary-600)">
                  {Array.from(typingUsers).join(', ')} {typingUsers.size > 1 ? 'are' : 'is'} typing...
                </Text>
              )}
            </Stack>
          </Box>

          <Divider />

          <Row gap="var(--ggui-spacing-2)">
            <Box style={{ flex: 1 }}>
              <Input
                label="Message"
                aria-label="Type your message here"
                value={input}
                onChange={(e: any) => setInput(e.target.value)}
                placeholder="Type a message..."
                onKeyDown={(e: React.KeyboardEvent) => e.key === 'Enter' && handleSend()}
              />

            </Box>
            <Button
              as={Clickable}
              onClick={handleSend}
              disabled={!input.trim()}
            >
              Send
            </Button>
          </Row>
        </Stack>
      </Card>
    </Container>
  );


}

