        </Card>

        <Row justify="between">
          <Button as={Clickable} variant="ghost" onClick={prevStep} disabled={step === 1}>Back</Button>
          {step < 3 ? (
            <Button as={Clickable} onClick={nextStep} disabled={step === 1 && !isStep1Valid}>Next</Button>
          ) : (
            <Button as={Clickable} variant="primary" onClick={submit}>Complete Setup</Button>
          )}
        </Row>
      </Stack>
    </Container>
  );
}
